B.SG=s(["True","False"],t.s)
B.Qx=new A.aF("b_misc_2","dart_fundamentals","Types",B.aC,B.hB,"Dart is a statically typed language.","True","Dart is statically typed with type inference. The analyzer checks types at compile time, but you can use dynamic to opt out of static checking.",B.SG,0)
B.Pw=new A.aF("b_misc_3","layouts","Themes",B.aC,B.B,"How do you apply a consistent theme across a Flutter app?","Pass a ThemeData to MaterialApp's theme parameter. Access it anywhere via Theme.of(context). Override locally with Theme widget.","MaterialApp(theme: ThemeData(colorScheme: ColorScheme.fromSeed(seedColor: Colors.blue)));\nAccess: Theme.of(context).colorScheme.primary",null,null)
